INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('EMAIL ADVANCED: Le warm-up domain ideal: J1-7=20/jour, J8-14=50/jour, J15-21=100/jour, J22+=200/jour. Progressif = reputation protegee.', 'Warmup domain: 20→50→100→200/jour progressif', 'email', 'best_practice', 0.93, 'massive_boost_10', 'system'),
('EMAIL ADVANCED: Les emails avec nombre impair de mots dans le sujet ont 5% plus d ouverture (perception de specificite).', 'Mots impairs sujet = +5% OR', 'email', 'insight', 0.78, 'massive_boost_10', 'system'),
('EMAIL ADVANCED: Le framework STAR pour les temoignages email: Situation → Tache → Action → Resultat.', 'Framework STAR temoignages email', 'email', 'best_practice', 0.85, 'massive_boost_10', 'system'),
('EMAIL ADVANCED: L envoi fractionne (staggered sending) sur 2-4h protege la reputation mieux que l envoi en masse instantane.', 'Envoi fractionne 2-4h = meilleure reputation', 'email', 'best_practice', 0.90, 'massive_boost_10', 'system'),
('EMAIL ADVANCED: Le sunset policy: desactiver automatiquement les contacts inactifs depuis 6 mois. Ameliore la delivrabilite de 20%.', 'Sunset 6 mois = +20% delivrabilite', 'email', 'best_practice', 0.90, 'massive_boost_10', 'system'),
('CONTENT ADVANCED: Le meme marketing (images humoristiques de la culture internet) genere 8x plus de partages mais doit etre aligne avec la marque.', 'Meme marketing = 8x partages (si aligne marque)', 'content', 'insight', 0.80, 'massive_boost_10', 'system'),
('CONTENT ADVANCED: Le contenu polarisant (position forte sur un sujet) genere 3x plus d engagement mais peut aliener une partie de l audience.', 'Contenu polarisant = 3x engagement (risque alienation)', 'content', 'insight', 0.78, 'massive_boost_10', 'system'),
('CONTENT ADVANCED: Les series de contenu (partie 1, 2, 3...) augmentent le taux de retour de 2x et creent de l anticipation.', 'Series contenu = 2x retour + anticipation', 'content', 'best_practice', 0.88, 'massive_boost_10', 'system'),
('CONTENT ADVANCED: Le contenu genere par IA + touche humaine (editing, personnalisation) = meilleur ratio qualite/productivite.', 'IA + touche humaine = meilleur ratio', 'content', 'best_practice', 0.90, 'massive_boost_10', 'system'),
('CONTENT ADVANCED: Le newsjacking (surfer sur une actualite chaude) dans les 4h genere 10x plus de visibilite que le contenu planifie.', 'Newsjacking < 4h = 10x visibilite', 'content', 'insight', 0.82, 'massive_boost_10', 'system'),
('SEO ADVANCED: Le concept de "link velocity": gagner des backlinks trop vite = suspect pour Google. 5-10 nouveaux liens/mois = naturel.', 'Link velocity: 5-10 liens/mois = naturel', 'seo', 'best_practice', 0.85, 'massive_boost_10', 'system'),
('SEO ADVANCED: Le content pruning (supprimer/consolider les pages a faible trafic) ameliore le classement global de 20%.', 'Content pruning = +20% classement global', 'seo', 'best_practice', 0.88, 'massive_boost_10', 'system'),
('SEO ADVANCED: Les core web vitals sont un facteur de classement mobile depuis 2021. LCP < 2.5s, FID < 100ms, CLS < 0.1.', 'Core web vitals: LCP 2.5s, FID 100ms, CLS 0.1', 'seo', 'best_practice', 0.93, 'massive_boost_10', 'system'),
('SEO ADVANCED: Le schema markup FAQ + HowTo + LocalBusiness = triple boost dans les rich snippets Google.', 'Triple schema: FAQ + HowTo + LocalBusiness', 'seo', 'best_practice', 0.88, 'massive_boost_10', 'system'),
('SEO ADVANCED: Les pages cornerstone (contenu pilier 3000+ mots) doivent etre linkees depuis toutes les pages secondaires du meme sujet.', 'Cornerstone 3000+ mots + liens internes', 'seo', 'best_practice', 0.90, 'massive_boost_10', 'system'),
('COMMERCIAL ADVANCED: Le multithread selling: contacter 3+ personnes dans la meme entreprise augmente le close rate de 35%.', 'Multithread 3+ contacts = +35% close rate', 'commercial', 'best_practice', 0.85, 'massive_boost_10', 'system'),
('COMMERCIAL ADVANCED: Le champion selling: identifier 1 personne interne enthousiaste qui vendra pour vous en interne.', 'Champion selling: 1 enthousiaste interne', 'commercial', 'best_practice', 0.82, 'massive_boost_10', 'system'),
('COMMERCIAL ADVANCED: Le MEDDIC framework: Metrics, Economic buyer, Decision criteria, Decision process, Identify pain, Champion.', 'MEDDIC: qualification enterprise', 'commercial', 'best_practice', 0.85, 'massive_boost_10', 'system'),
('COMMERCIAL ADVANCED: Le compte rendu d appel envoye dans l heure augmente le taux de progression pipeline de 25%.', 'CR appel < 1h = +25% progression pipeline', 'commercial', 'best_practice', 0.88, 'massive_boost_10', 'system'),
('COMMERCIAL ADVANCED: Le mutual action plan (plan d action partage avec le prospect) augmente le close rate de 40%.', 'Mutual action plan = +40% close rate', 'commercial', 'best_practice', 0.85, 'massive_boost_10', 'system'),
('DM ADVANCED: Le voice note Instagram (< 15s) a un taux d ouverture de 98% et un taux de reponse de 45%.', 'Voice note IG < 15s = 98% ouverture, 45% reponse', 'dm_instagram', 'best_practice', 0.85, 'massive_boost_10', 'system'),
('DM ADVANCED: Commenter 3 posts du prospect avant d envoyer un DM ("warm-up social") augmente la reponse de 4x.', 'Warm-up social 3 posts avant DM = 4x reponse', 'dm_instagram', 'best_practice', 0.90, 'massive_boost_10', 'system'),
('DM ADVANCED: Le DM video personnalise (dire le nom du prospect + son business) a un taux de reponse de 50%.', 'DM video personnalise = 50% reponse', 'dm_instagram', 'insight', 0.82, 'massive_boost_10', 'system'),
('DM ADVANCED: Les DMs envoyes depuis un compte a 1000+ followers recoivent 2x plus de reponses (credibilite).', 'Compte 1000+ followers DM = 2x reponses', 'dm_instagram', 'insight', 0.80, 'massive_boost_10', 'system'),
('DM ADVANCED: La technique du "slide in": reagir a une story → compliment → question → conversation → pitch (jamais en 1er DM).', 'Slide in: story → compliment → question → conversation → pitch', 'dm_instagram', 'best_practice', 0.88, 'massive_boost_10', 'system'),
('WHATSAPP ADVANCED: Le message de suivi post-achat (satisfaction + avis) augmente la retention de 35% et les avis Google de 3x.', 'Suivi post-achat WhatsApp = +35% retention +3x avis', 'whatsapp', 'best_practice', 0.88, 'massive_boost_10', 'system'),
('WHATSAPP ADVANCED: Les messages avec location sharing (envoyer la localisation du magasin) augmentent les visites de 20%.', 'Location sharing WhatsApp = +20% visites', 'whatsapp', 'insight', 0.80, 'massive_boost_10', 'system'),
('WHATSAPP ADVANCED: Le chatbot WhatsApp avec menu interactif (liste de boutons) reduit le temps de reponse de 80%.', 'Chatbot WhatsApp menu = -80% temps reponse', 'whatsapp', 'best_practice', 0.85, 'massive_boost_10', 'system'),
('CHATBOT ADVANCED: Le chatbot qui detecte le sentiment (frustre, curieux, presse) et adapte son ton augmente la satisfaction de 45%.', 'Chatbot detection sentiment = +45% satisfaction', 'chatbot', 'best_practice', 0.85, 'massive_boost_10', 'system'),
('CHATBOT ADVANCED: Proposer 3 questions suggees au debut de la conversation augmente l engagement de 60%.', 'Questions suggerees chatbot = +60% engagement', 'chatbot', 'best_practice', 0.88, 'massive_boost_10', 'system'),
('CHATBOT ADVANCED: Le chatbot qui envoie un recap par email apres la conversation augmente la conversion de 20%.', 'Recap email post-chatbot = +20% conversion', 'chatbot', 'best_practice', 0.82, 'massive_boost_10', 'system'),
('TIKTOK ADVANCED: Le format "storytime" (raconter une anecdote) a le meilleur taux de completion (75%) de tous les formats.', 'Storytime TikTok = 75% completion', 'tiktok_comments', 'insight', 0.85, 'massive_boost_10', 'system'),
('TIKTOK ADVANCED: Poster le meme contenu 3x avec 3 hooks differents: 1 marchera forcement. Tester les hooks est la cle.', 'TikTok: meme contenu 3 hooks = tester', 'tiktok_comments', 'best_practice', 0.85, 'massive_boost_10', 'system'),
('TIKTOK ADVANCED: Le green screen (fond d ecran personnalise) avec du texte a l ecran a 2x plus de completion que la video classique.', 'Green screen + texte TikTok = 2x completion', 'tiktok_comments', 'insight', 0.80, 'massive_boost_10', 'system'),
('ADS ADVANCED: Le creative fatigue (baisse de performance apres 7-10 jours) impose de rafraichir les creatives chaque semaine.', 'Creative fatigue: rafraichir chaque semaine', 'ads', 'best_practice', 0.90, 'massive_boost_10', 'system'),
('ADS ADVANCED: Les audiences similaires (lookalike 1%) sont les plus precises. Au-dela de 5%, la precision diminue fortement.', 'Lookalike 1% = plus precis, > 5% = imprecis', 'ads', 'best_practice', 0.88, 'massive_boost_10', 'system'),
('ADS ADVANCED: Le retargeting sequentiel (J1 benefice → J3 temoignage → J7 offre) convertit 3x mieux que le retargeting repetitif.', 'Retargeting sequentiel = 3x conversion', 'ads', 'best_practice', 0.88, 'massive_boost_10', 'system'),
('ADS ADVANCED: Les publicites video qui montrent le produit dans les 3 premieres secondes ont 30% plus de conversions.', 'Produit dans 3s = +30% conversions ads', 'ads', 'best_practice', 0.85, 'massive_boost_10', 'system'),
('ADS ADVANCED: Le broad targeting + creatives fortes > le ciblage precis + creatives faibles. L algo Meta optimise mieux avec du volume.', 'Broad + bonnes creatives > ciblage precis + faibles creatives', 'ads', 'insight', 0.85, 'massive_boost_10', 'system'),
('GMAPS ADVANCED: Les photos geolockees (avec metadonnees GPS) sont mieux classees dans Google Maps que les photos sans.', 'Photos geotaggees GMaps = mieux classees', 'gmaps', 'best_practice', 0.82, 'massive_boost_10', 'system'),
('GMAPS ADVANCED: Demander un avis apres un moment positif (fin de repas, resultat visible) augmente la note moyenne de 0.3.', 'Demande avis moment positif = +0.3 note', 'gmaps', 'best_practice', 0.85, 'massive_boost_10', 'system'),
('GMAPS ADVANCED: Les businesses qui repondent a 100% des avis apparaissent 2x plus souvent dans le pack local Google.', 'Reponse 100% avis = 2x pack local', 'gmaps', 'best_practice', 0.88, 'massive_boost_10', 'system'),
('RETENTION ADVANCED: Le health score client (connexion + usage + satisfaction) predit le churn 30 jours a l avance avec 80% de precision.', 'Health score predit churn 30j a 80%', 'retention', 'insight', 0.88, 'massive_boost_10', 'system'),
('RETENTION ADVANCED: Les customers a risque (health score < 40) recontactes proactivement ont 60% de chances d etre sauves.', 'Contact proactif risque = 60% sauve', 'retention', 'best_practice', 0.88, 'massive_boost_10', 'system'),
('RETENTION ADVANCED: Le rapport de valeur mensuel automatique ("Voici ce que vos agents ont fait") est le #1 outil anti-churn.', 'Rapport valeur mensuel = #1 anti-churn', 'retention', 'best_practice', 0.93, 'massive_boost_10', 'system'),
('ONBOARDING ADVANCED: Les clients qui completent l onboarding en < 24h ont un taux de retention 3x superieur a ceux qui prennent > 7 jours.', 'Onboarding < 24h = 3x retention vs > 7j', 'onboarding', 'insight', 0.90, 'massive_boost_10', 'system'),
('ONBOARDING ADVANCED: Le message de felicitation apres chaque etape completee (gamification) augmente le taux de completion de 40%.', 'Felicitation gamifiee = +40% completion', 'onboarding', 'best_practice', 0.88, 'massive_boost_10', 'system'),
('ONBOARDING ADVANCED: Le "buddy system" (assigner un client existant comme mentor au nouveau) reduit le churn de 35%.', 'Buddy system onboarding = -35% churn', 'onboarding', 'insight', 0.80, 'massive_boost_10', 'system'),
('FINANCE ADVANCED: Le cash flow forecast a 13 semaines est l outil #1 de survie des PME. Jamais de surprise.', 'Cash flow forecast 13 semaines = survie PME', 'comptable', 'best_practice', 0.90, 'massive_boost_10', 'system'),
('FINANCE ADVANCED: Le ratio endettement / capitaux propres doit rester < 1. Au-dessus, la structure financiere est fragile.', 'Ratio dette/capitaux < 1', 'comptable', 'best_practice', 0.88, 'massive_boost_10', 'system'),
('CEO ADVANCED: Le OKR framework (Objectives + Key Results) est le meilleur pour aligner toute l equipe sur les priorites trimestrielles.', 'OKR framework: aligner equipe trimestriel', 'ceo', 'best_practice', 0.90, 'massive_boost_10', 'system'),
('CEO ADVANCED: Le weekly all-hands (15 min max): KPIs, wins, blocages, priorities. Maintient l alignement meme a distance.', 'All-hands weekly 15min: KPIs wins blocages prio', 'ceo', 'best_practice', 0.85, 'massive_boost_10', 'system'),
('CEO ADVANCED: Le decision-making framework RAPID: Recommend, Agree, Perform, Input, Decide. Clarifie qui fait quoi.', 'RAPID: Recommend Agree Perform Input Decide', 'ceo', 'best_practice', 0.82, 'massive_boost_10', 'system'),
('SHARED ADVANCED: Le customer lifetime value (LTV) se calcule: ARPU × marge brute × duree de vie moyenne. C est LA metrique.', 'LTV = ARPU × marge × duree vie', NULL, 'best_practice', 0.92, 'massive_boost_10', 'system'),
('SHARED ADVANCED: Le Net Revenue Retention (NRR) > 100% signifie que les clients existants depensent plus chaque annee. Le graal SaaS.', 'NRR > 100% = expansion revenus existants', NULL, 'insight', 0.90, 'massive_boost_10', 'system'),
('SHARED ADVANCED: Les entreprises customer-centric croissent 6x plus vite que celles centrées produit.', 'Customer-centric = 6x croissance', NULL, 'insight', 0.88, 'massive_boost_10', 'system'),
('SHARED ADVANCED: Le "jobs to be done" framework: les clients n achetent pas un produit, ils "embauchent" une solution pour un job specifique.', 'Jobs to be done: solution pour un job', NULL, 'insight', 0.85, 'massive_boost_10', 'system'),
('SHARED ADVANCED: La methode Eisenhower pour prioriser: Urgent+Important=FAIRE, Important+PasUrgent=PLANIFIER, Urgent+PasImportant=DELEGUER.', 'Eisenhower: faire, planifier, deleguer, eliminer', NULL, 'best_practice', 0.90, 'massive_boost_10', 'system'),
('SHARED ADVANCED: Le principe de Pareto (80/20): 80% des resultats viennent de 20% des actions. Identifier et doubler les 20%.', 'Pareto 80/20: identifier et doubler les 20%', NULL, 'best_practice', 0.92, 'massive_boost_10', 'system'),
('SHARED ADVANCED: Les micro-moments Google: "Je veux savoir", "Je veux aller", "Je veux faire", "Je veux acheter". Etre present a chaque.', 'Micro-moments Google: savoir, aller, faire, acheter', NULL, 'insight', 0.85, 'massive_boost_10', 'system')
